import math

def euclidean_distance(p1, p2):
    return math.sqrt(sum((c1 - c2) ** 2 for c1, c2 in zip(p1, p2)))

def k_centers_greedy(points, k):
    if k <= 0:
        return []
    if k >= len(points):
        return list(points)

    centers = []
    centers.append(points[0])

    for _ in range(k - 1):
        max_min_dist = -1
        next_center = None

        for p in points:
            if p in centers:
                continue

            min_dist_to_current_centers = float('inf')
            for c in centers:
                dist = euclidean_distance(p, c)
                if dist < min_dist_to_current_centers:
                    min_dist_to_current_centers = dist

            if min_dist_to_current_centers > max_min_dist:
                max_min_dist = min_dist_to_current_centers
                next_center = p

        if next_center is not None:
            centers.append(next_center)
        else:
            break

    return centers
